from flask import Flask, request, jsonify
from uuid import uuid4
import threading
import time

# Simulación de la clase Orchestrator
class Orchestrator:
    def __init__(self):
        self.projects = {}

    def run(self, spec):
        # Genera un ID único para el proyecto
        project_id = str(uuid4())
        self.projects[project_id] = {"status": "running", "spec": spec}

        # Simula un proceso de ejecución en un hilo separado
        def simulate_execution():
            time.sleep(2)  # Simula tiempo de ejecución
            self.projects[project_id]["status"] = "completed"

        threading.Thread(target=simulate_execution).start()
        return project_id

    def status(self, project_id):
        return self.projects.get(project_id, {"status": "not_found"})

# Configuración de Flask
app = Flask(__name__)
orchestrator = Orchestrator()

@app.route('/run', methods=['POST'])
def run():
    data = request.get_json()
    if not data or 'spec' not in data:
        return jsonify({"error": "Invalid input"}), 400
    project_id = orchestrator.run(data['spec'])
    return jsonify({"project_id": project_id}), 200

@app.route('/status/<project_id>', methods=['GET'])
def status(project_id):
    status = orchestrator.status(project_id)
    return jsonify(status), 200

