    import requests
    from multiprocessing import Process
    import time

    # Iniciar la aplicación Flask en un proceso separado
    def start_server():
        app.run(port=5000)

    server_process = Process(target=start_server)
    server_process.start()
    time.sleep(1)  # Esperar a que el servidor inicie

    try:
        # Prueba del criterio de aceptación
        base_url = "http://127.0.0.1:5000"

        # Enviar solicitud POST /run
        response = requests.post(f"{base_url}/run", json={"spec": "test_spec"})
        if response.status_code != 200:
            print(f"CRITERIO FALLO: POST /run devolvió {response.status_code}")
        else:
            project_id = response.json().get("project_id")
            if not project_id:
                print("CRITERIO FALLO: No se devolvió project_id en POST /run")
            else:
                # Verificar estado inicial con GET /status/{project_id}
                response = requests.get(f"{base_url}/status/{project_id}")
                if response.status_code != 200:
                    print(f"CRITERIO FALLO: GET /status devolvió {response.status_code}")
                elif response.json().get("status") != "running":
                    print(f"CRITERIO FALLO: Estado inicial no es 'running'")
                else:
                    # Esperar a que el proceso termine
                    time.sleep(3)
                    response = requests.get(f"{base_url}/status/{project_id}")
                    if response.status_code != 200:
                        print(f"CRITERIO FALLO: GET /status devolvió {response.status_code} tras esperar")
                    elif response.json().get("status") != "completed":
                        print(f"CRITERIO FALLO: Estado final no es 'completed'")
                    else:
                        print("CRITERIO OK")
    except Exception as e:
        print(f"CRITERIO FALLO: {e}")
    finally:
        server_process.terminate()
        server_process.join()
